import { Request, Response } from 'express';
import { GroupService } from './group.service';
import { GroupValidator } from './group.validator';
import { GroupCreateDTO } from './group.dto';
import { AppError } from '../../middlewares/error-handler';
import { validateRequest } from '../../validators/validate-request';

export class GroupController {
  constructor(private groupService: GroupService) {}

  public async createGroup(req: Request, res: Response): Promise<void> {
    const { userId } = req;
    const dto = validateRequest<GroupCreateDTO>(GroupValidator.create, req.body);

    try {
      const group = await this.groupService.createGroup(dto, userId);
      res.status(201).json({ success: true, data: group, meta: { requestId: '', timestamp: new Date().toISOString(), version: 'v1' } });
    } catch (error) {
      throw new AppError('group/create_failed', 'Failed to create group', 500);
    }
  }

  public async getGroupById(req: Request, res: Response): Promise<void> {
    const { id } = req.params;
    try {
      const group = await this.groupService.getGroupById(id, req.userId);
      res.json({ success: true, data: group, meta: { requestId: '', timestamp: new Date().toISOString(), version: 'v1' } });
    } catch (error) {
      throw new AppError('group/not_found', 'Group not found', 404);
    }
  }
}

import { GroupRepository } from './group.repository';
import { GroupCreateDTO } from './group.dto';

export class GroupService {
  constructor(private groupRepository: GroupRepository) {}

  public async createGroup(dto: GroupCreateDTO, userId: string) {
    return this.groupRepository.create({ ...dto, adminId: userId, createdAt: new Date() });
  }

  public async getGroupById(id: string, userId: string) {
    const group = await this.groupRepository.findById(id);
    if (!group) throw new Error('Group not found');
    // Additional permission checks can go here
    return group;
  }
}

import { GroupModel } from './group.model';

export class GroupRepository {
  public async create(data: any) {
    const group = new GroupModel(data);
    return group.save();
  }

  public async findById(id: string) {
    return GroupModel.findById(id).exec();
  }
}

import { model, Schema } from 'mongoose';

interface Group {
  name: string;
  description: string;
  adminId: string;
  members: string[];
  telegramChatId?: string;
  createdAt: Date;
}

const groupSchema = new Schema<Group>({
  name: { type: String, required: true },
  description: { type: String, required: true },
  adminId: { type: Schema.Types.ObjectId, ref: 'User', required: true },
  members: [{ type: Schema.Types.ObjectId, ref: 'User' }],
  telegramChatId: { type: String },
  createdAt: { type: Date, default: Date.now },
});

export const GroupModel = model<Group>('Group', groupSchema);

export interface GroupCreateDTO {
  name: string;
  description: string;
}

import { z } from 'zod';

export const GroupValidator = {
  create: z.object({
    name: z.string().min(1, 'Name is required').max(100),
    description: z.string().min(1, 'Description is required').max(500),
  }),
};

export class AppError extends Error {
  public readonly statusCode: number;
  public readonly code: string;

  constructor(code: string, message: string, statusCode: number) {
    super(message);
    this.statusCode = statusCode;
    this.code = code;
  }
}

export const errorHandler = (err, req, res, next) => {
  if (err instanceof AppError) {
    res.status(err.statusCode).json({ success: false, error: { code: err.code, message: err.message } });
  } else {
    res.status(500).json({ success: false, error: { code: 'server_error', message: 'Internal Server Error' } });
  }
};

export const validateRequest = <T>(schema: any, body: any): T => {
  const result = schema.parse(body);
  return result as T;
};
